const input = $input.first().json;
const body = input.body || input;
const env = $env || {};
const now = new Date().toISOString();
const creator = body.creator || {};
const contact = creator.contact || {};
const message = body.message || {};
const confirmation = body.confirmation || {};
function clean(value) { return String(value ?? '').trim(); }
function fail(status, text) { return [{ json: { ok: false, readyToSend: false, queueId: body.queueId || '', status, source: 'n8n-email-send', crmStatus: 'ready_to_contact', dryRun: true, allowSend: false, message: text, updatedAt: now } }]; }

if (body.action !== 'record_sent') {
  return fail('blocked', 'Only record_sent requests can enter the email send workflow.');
}
if (body.allowSend !== true || body.dryRun !== false) {
  return fail('blocked', 'Email sending requires allowSend=true and dryRun=false after human confirmation.');
}
if (!confirmation.confirmedAt) {
  return fail('blocked', 'Human confirmation timestamp is required before sending.');
}
if (!clean(contact.email)) {
  return fail('needs_email', 'Creator email is missing. Add a public email before using SMTP send.');
}
if (!clean(message.draft)) {
  return fail('needs_message', 'Approved outreach draft is missing.');
}
if (env.CREATOR_EMAIL_SEND_ENABLED !== 'true') {
  return fail('needs_smtp_config', 'SMTP send is not enabled. Configure an n8n SMTP credential, set CREATOR_EMAIL_SEND_ENABLED=true, and set CREATOR_OUTREACH_FROM_EMAIL.');
}

const displayName = clean(creator.displayName) || clean(creator.handle).replace(/^@/, '') || 'creator';
return [{
  json: {
    ok: true,
    readyToSend: true,
    queueId: body.queueId || '',
    status: 'ready_to_send',
    source: 'n8n-email-send',
    crmStatus: 'ready_to_contact',
    dryRun: false,
    allowSend: true,
    creatorId: creator.id || '',
    creatorHandle: clean(creator.handle).replace(/^@/, ''),
    fromEmail: clean(env.CREATOR_OUTREACH_FROM_EMAIL || env.SMTP_FROM_EMAIL) || 'pr@tk-saas.local',
    toEmail: clean(contact.email),
    subject: clean(message.subject) || `Collaboration with ${displayName}`,
    text: clean(message.draft),
    confirmedAt: confirmation.confirmedAt,
    confirmedBy: confirmation.confirmedBy || 'operator',
    updatedAt: now,
  },
}];
